"""
MKT Context Commentary — Genesis chapters 46–48
Run: python3 scripts/zc-context-genesis-46-48.py

Source data used:
- data/interlinear/genesis.json
- data/translation/draft/mediating/genesis.json (MKT text)
- data/commentary/mkt-context/genesis.json (existing entries)

Key decisions in this range:
- Ch46: Genealogical material (vv8-27) receives brief-but-substantive entries noting
  ANE kinship functions of genealogies, the significance of 70 persons, Levi's sons as
  future priestly divisions, and the LXX's count of 75.
- Ch47: Joseph's land-consolidation policy is read against Egyptian administrative
  history (temple-land exemption is historically corroborated); the hand-under-thigh
  oath and Jacob's Heb 11:21 posture receive full treatment.
- Ch48: Adoption formula, the crossed-hands inversion, and the threefold divine name
  (God of the fathers / Shepherd / Angel-Redeemer) are the key contextual anchors.
  The gāʾal root appearing for a divine agent is flagged as theologically significant.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

# INTENT: mkt-context commentary for Genesis 46–48. Ch46 = descent to Egypt with
#   genealogy; ch47 = settlement in Goshen and Joseph's land policy; ch48 = Jacob
#   adopts Ephraim/Manasseh and crosses his hands. Egyptological background, ANE
#   kinship law, and covenant-number symbolism are the primary contexts.
# CHANGE? If data/commentary/mkt-context/genesis.json schema changes, update
#   load_comm/save_comm helpers in Z_COMMENTARY_SCRIPT_GUIDE.md accordingly.
# VERIFY: After running, python3 -c "import json; d=json.load(open('data/commentary/mkt-context/genesis.json')); print(len(d.get('46',{})), len(d.get('47',{})), len(d.get('48',{})))" should print "34 31 22".

NEW_DATA = {
"46": {
"1": "<p>Beersheba is the southernmost point of the traditional land of Israel and historically a sacred site for the patriarchs: Isaac built an altar there (26:23&#8211;25), and Jacob had earlier passed through it (28:10). Offering sacrifices there before departing for Egypt is an act of covenant loyalty at the boundary of the promised land&#8212;Jacob worships at the last Yahwistic sanctuary before entering a land of foreign gods. The name &#8220;God of his father Isaac&#8221; links the journey to the Abrahamic promise-chain running through Isaac.</p>",
"2": "<p>The double-name call &#8220;Jacob! Jacob!&#8221; (<em>yaʿăqōb yaʿăqōb</em>) is a divine address pattern used at high-stakes theophanic moments: &#8220;Abraham! Abraham!&#8221; (22:11), &#8220;Moses! Moses!&#8221; (Exod 3:4), &#8220;Samuel! Samuel!&#8221; (1 Sam 3:10). The repetition signals urgent divine communication rather than ordinary speech. Jacob&#8217;s response <em>hinneni</em> (&#8220;Here I am&#8221;) is the readiness-formula of covenant agents throughout Scripture (Abraham 22:1; Moses Exod 3:4; Isaiah Isa 6:8). God addresses him by the pre-Bethel name &#8220;Jacob&#8221; rather than &#8220;Israel,&#8221; perhaps emphasizing the personal rather than national dimension of the call.</p>",
"3": "<p>&#8220;Do not be afraid to go down to Egypt.&#8221; The divine reassurance implies that the descent was religiously troubling. Egypt was not the promised land; going there risked covenant rupture or the absorption of the covenant family into a foreign culture. Abraham had gone to Egypt in famine (12:10) and it had nearly ended catastrophically. Isaac had been explicitly prohibited from going to Egypt (26:2). The divine command here overrides the general prohibition: this descent is within God&#8217;s plan. The promise &#8220;I will make you into a great nation there&#8221; is the Abrahamic fruitfulness promise (12:2; 17:6) reactivated in an unexpected location&#8212;Egypt, not Canaan, will be the incubator of the nation.</p>",
"4": "<p>&#8220;I will go down to Egypt with you, and I will surely bring you back again.&#8221; The divine accompaniment (&#8220;with you&#8221;) is the fundamental covenant assurance: YHWH is not a territorial deity tied to Canaan. He can go to Egypt and remain Israel&#8217;s God there&#8212;a radical claim in an ANE world where crossing territorial boundaries meant leaving one god&#8217;s jurisdiction and entering another&#8217;s. &#8220;Joseph&#8217;s own hand will close your eyes&#8221;&#8212;the personal dying-rite of a favored son attending the patriarch&#8217;s death was the highest social comfort available. Jacob had given up Joseph for dead; God promises the reunion will culminate in Joseph&#8217;s faithful presence at Jacob&#8217;s end.</p>",
"5": "<p>The &#8220;carts (<em>ʿăgālôt</em>) that Pharaoh had sent&#8221; are an Egyptian-style conveyance&#8212;wheeled wagons&#8212;unusual in Canaan where pack animals were standard for travel. Egyptian reliefs and texts from the New Kingdom document wheeled wagons used for transport of high-status passengers and goods; Canaanite terrain of highlands was poorly suited for wheeled vehicles, but the Nile Delta flatlands used them extensively. The carts signal Pharaoh&#8217;s royal hospitality extended to Jacob&#8217;s entire household&#8212;a logistically significant provision for moving a large extended family with children, elderly, and possessions.</p>",
"6": "<p>&#8220;They also took with them their livestock and the possessions they had acquired in Canaan.&#8221; The family&#8217;s movement is presented as a full migration, not a temporary famine-refuge visit. They bring their wealth (livestock = wealth in pastoral economy) rather than leaving it behind. This details the irrevocability of the move: Jacob is not sending scouts or a temporary purchasing delegation but relocating his entire economic base. The phrase &#8220;all his descendants&#8221; (<em>kol-zarʿô</em>) anticipates the genealogical list that follows and frames it as the totality of the covenant seed entering Egypt.</p>",
"7": "<p>&#8220;Sons and grandsons&#8230; daughters and granddaughters&#8212;all his descendants.&#8221; The inclusion of daughters and granddaughters in the descent-notice is unusual; the genealogical list that follows (vv8&#8211;25) is almost exclusively male. Only Dinah (v15) and Serah (v17) are named among the women. The notice that daughters and granddaughters went is important: the covenant community&#8217;s physical survival in Egypt depends on the presence of the entire family, not just the male line. Egypt will be the place where the family becomes a people&#8212;fruitfulness requiring both sexes.</p>",
"8": "<p>The genealogical list (vv8&#8211;25) serves multiple ANE functions simultaneously: it establishes legal kinship claims (these 70 people are documented members of one family), it provides the tribal ancestry for Israel&#8217;s twelve tribes, and it creates a documentary basis for the Exodus claim that Israel left Egypt as a distinct people rather than a mixed population. The list in vv8&#8211;25 is the authoritative form of Israel&#8217;s tribal origins; parallel lists appear in Num 26 and 1 Chron 2&#8211;8 with variations reflecting later tribal history.</p>",
"9": "<p>Reuben&#8217;s four sons (Hanoch, Pallu, Hezron, Carmi) are the eponymous ancestors of four Reubenite clans documented in Num 26:5&#8211;11. Genealogical lists in the ANE regularly use personal names for what are in fact tribal sub-units: &#8220;Hezron&#8221; is simultaneously an individual in Jacob&#8217;s household and the name of a clan that exists for centuries. The list preserves the tribal memory of Reuben&#8217;s subdivision into four clans, anchored to the Egypt descent as its founding moment.</p>",
"10": "<p>Simeon&#8217;s six sons include &#8220;Shaul the son of a Canaanite woman&#8221;&#8212;the parenthetical note flags a mixed lineage in the genealogy. The Canaanite mother is unnamed but her ethnic identity is recorded as significant; her son becomes an ancestor of a Simeonite sub-clan. The concern about Canaanite intermarriage (explicitly addressed in ch 24, 26:34&#8211;35, 28:1) appears here as a genealogical annotation rather than a narrative crisis. Simeon&#8217;s own connection to Canaan (the Shechem massacre, ch 34) may make his son&#8217;s Canaanite lineage especially notable.</p>",
"11": "<p>Levi&#8217;s three sons — Gershon, Kohath, and Merari — are the eponymous ancestors of the three Levitical clans assigned distinct tabernacle duties in Num 3&#8211;4. The audience reading Genesis knew these names as the organizational structure of Israel&#8217;s priesthood: Kohath&#8217;s descendants included Moses and Aaron (Exod 6:16&#8211;20); the Gershonites and Merarites carried different sections of the tabernacle. The brevity of the entry — only three names — contrasts with the elaborate Levitical genealogies of Chronicles, but these three names carry enormous structural weight for Israel&#8217;s entire worship system.</p>",
"12": "<p>Judah&#8217;s entry parenthetically notes that Er and Onan &#8220;had died in the land of Canaan&#8221;&#8212;the deaths narrated in ch 38 (Er and Onan&#8217;s deaths due to wickedness, the Tamar episode). The parenthetical integrates the scandalous ch 38 narrative into the formal genealogy without erasing it: the dead sons are listed but marked as having pre-deceased the Egypt descent. Perez and Zerah&#8212;Tamar&#8217;s sons by Judah&#8212;appear in the list, legitimizing their ancestry despite the irregular circumstances of their conception. Perez is the ancestor of David and, through him, of Jesus (Ruth 4:18&#8211;22; Matt 1:3).</p>",
"13": "<p>Issachar&#8217;s four sons (Tola, Puah, Jashub, Shimron) are documented in Num 26:23&#8211;25. Tola&#8217;s name appears again as a judge of Israel (Judg 10:1&#8211;2). The genealogy thus bridges the Egypt descent and the later period of the judges, establishing that the Israelite population that eventually occupied Canaan traced its ancestry directly to this list of seventy souls who entered Egypt. The genealogical list is tribal memory encoded as personal history.</p>",
"14": "<p>Zebulun&#8217;s three sons appear again in Num 26:26&#8211;27. Zebulun&#8217;s territory in the later tribal allotment lay in the lower Galilee region between Asher and Issachar; its genealogical roots here in the Egypt descent establish its claim within the covenant family. The minimal genealogical entries for Issachar and Zebulun (as opposed to the more detailed entries for Judah and Benjamin) reflect the relative significance of these tribes in later Israelite national memory.</p>",
"15": "<p>The summary count for Leah&#8217;s line — 33 persons — excludes daughters-in-law but includes Dinah (the only daughter named). &#8220;In Paddan Aram&#8221; specifies where Jacob&#8217;s Leah-sons were born, distinguishing them from those conceived later or in Canaan. The genealogical totals (33 + 16 + 14 + 7 = 70 direct descendants) represent precise tribal bookkeeping. The number 33 for Leah&#8217;s line establishes her sons&#8217; descendants as the dominant bloc in the covenant family&#8212;six of the twelve tribes plus the priestly line of Levi.</p>",
"16": "<p>Gad&#8217;s seven sons are among the most in any tribe&#8217;s listing. Gad&#8217;s territory in the later allotment lay in the Transjordan (Num 32:34&#8211;36); his genealogy here establishes the tribal roots before the Egypt sojourn. The names Zephon, Haggi, Shuni, Ezbon, Eri, Arodi, Areli are otherwise unattested outside Numbers 26:15&#8211;18 (with slight variations), suggesting these clan names were preserved in oral tradition even if the individuals are otherwise unknown.</p>",
"17": "<p>Asher&#8217;s line uniquely includes a named daughter — Serah — alongside her brothers and nephews. Serah bat Asher appears again in Num 26:46 as a surviving member of the original Egypt family; Jewish tradition celebrates her as an exceptionally long-lived figure who was present at both the Egypt entry and the Exodus, serving as a living link between the generations. Her inclusion in this tribal genealogy by name, without a son being listed for her, is unusual and suggests she held a recognized position in Israelite memory independent of her sons.</p>",
"18": "<p>Zilpah&#8217;s line — Leah&#8217;s maidservant and mother of Gad and Asher — totals 16. The genealogical list respects the social stratification of Jacob&#8217;s household: wives&#8217; sons and concubine-sons are listed separately, with totals noted for each maternal line. This structure mirrors the ANE legal distinction between primary wives and secondary wives/concubines with respect to inheritance rights (cf. Hammurabi §170&#8211;171 on the inheritance rights of sons by slave-wives). All four maternal lines are included in the covenant count of 70, however — status distinctions within the family are preserved but do not exclude anyone from the covenant people.</p>",
"19": "<p>Rachel&#8217;s line receives the briefest introduction: &#8220;The sons of Jacob&#8217;s wife Rachel: Joseph and Benjamin.&#8221; The possessive &#8220;Jacob&#8217;s wife Rachel&#8221; — emphasizing her status as primary wife — is unique in the list; no other wife is so designated. Only two direct sons are listed because Joseph&#8217;s sons (born in Egypt, v20) and Benjamin&#8217;s sons (v21) extend the line. Rachel&#8217;s two sons are the most narratively prominent of all Jacob&#8217;s children&#8212;their stories dominate Genesis 37&#8211;50.</p>",
"20": "<p>Manasseh and Ephraim — born in Egypt to Asenath, daughter of Potiphera priest of On (Heliopolis) — are included in the Egypt descent genealogy even though they were born in Egypt before the family arrived. Their inclusion is legally necessary: they will be adopted by Jacob (ch 48) and need to appear in the foundational family register. Their Egyptian mother is noted without comment — the genealogy does not elide their mixed heritage, though Jacob&#8217;s adoption in ch 48 will give them full Israelite tribal status regardless.</p>",
"21": "<p>Benjamin&#8217;s ten sons are listed — the most sons of any tribe, which does not correspond to the historical situation of Benjamin as one of the smallest tribes (Judg 20:46&#8211;47). Some of the ten names may represent later clan names rather than biological sons of the Benjamin who went to Egypt; genealogical lists in the ANE regularly assign second-generation clans to the original ancestor. Benjamin was young enough at the Egypt descent that ten adult sons would be unlikely; this may reflect a later genealogical expansion encoding Benjaminite clan history.</p>",
"22": "<p>Rachel&#8217;s fourteen descendants (Joseph + his 2 sons + Benjamin + his 10 sons = 14) form the smallest maternal-line total, reflecting Rachel&#8217;s late marriage to Jacob and her early death. The fourteen are disproportionately prominent in the narrative: Joseph dominates Genesis 37&#8211;50, and Benjamin is the focal point of chs 42&#8211;45. The two Joseph tribes (Ephraim and Manasseh) will become the most populous of the northern tribes after the Exodus&#8212;quantity of influence and quantity of genealogical entries are inversely proportional in this list.</p>",
"23": "<p>Dan&#8217;s single son, Hushim, is the minimal genealogical entry in the list. Dan later becomes a significant tribe (its territory spans from the Shephelah into Dan in the north), and its genealogy expands in later texts (Num 26:42&#8211;43). The single entry here may reflect Dan&#8217;s small beginning or the loss of additional genealogical records. Genealogical minimalism in ANE lists often indicated a tribe that had not yet fully differentiated into sub-clans at the time the list was compiled.</p>",
"24": "<p>Naphtali&#8217;s four sons (Jahzeel, Guni, Jezer, Shillem) correspond to the four Naphtalite clans in Num 26:48&#8211;50. Naphtali&#8217;s territory in the later allotment was the northern Galilee highlands, strategically significant as border territory with Syria. The inclusion of these four names in the Egypt descent genealogy establishes the Naphtalite tribal identity as rooted in the same foundational moment as all other tribes.</p>",
"25": "<p>Bilhah&#8217;s seven descendants (Dan&#8217;s one + Naphtali&#8217;s four + two grandsons?) complete the four maternal-line totals. The total of 7 for the concubine Bilhah and 16 for the concubine Zilpah, versus 33 for Leah and 14 for Rachel, reflects the social hierarchy of the household while insisting that all four lines are covenant participants. The ANE genealogical function is preserved: the family that entered Egypt is precisely enumerated as the family that will eventually emerge from Egypt, providing the basis for tribal identity claims in the land.</p>",
"26": "<p>Sixty-six direct descendants — &#8220;those who were his direct descendants, not counting his sons&#8217; wives.&#8221; The precision matters: the 66 excludes Jacob himself, Joseph, and Joseph&#8217;s two sons (who were already in Egypt). The number 66 thus represents the core of the Israel-family who made the Egypt descent. In ANE census tradition, household counts that excluded certain categories (wives, slaves, servants) were common; this count represents the male and female direct descendants who constitute the covenant seed entering Egypt.</p>",
"27": "<p>Seventy total — &#8220;with the two sons who had been born to Joseph in Egypt, the members of Jacob&#8217;s family who went to Egypt totaled seventy.&#8221; The number 70 carries significant symbolic freight in the Hebrew Bible: 70 nations in the Table of Nations (ch 10), 70 elders of Israel at Sinai (Exod 24:1), 70 years of exile (Jer 25:11), 70 &#8220;weeks&#8221; in Dan 9. The LXX counts 75, including additional grandsons of Joseph not in the Hebrew text; Acts 7:14 follows the LXX. Both numbers have ancient manuscript authority; the Hebrew&#8217;s 70 is the more symbolically resonant figure in Jewish tradition, connecting the family-count to the nations-count: 70 souls entering Egypt corresponds to 70 nations in the world.</p>",
"28": "<p>Judah is sent ahead &#8220;to get directions to Goshen&#8221; — his role as the family&#8217;s forward agent signals his leadership status (anticipated in ch 44:18&#8211;34, where Judah speaks for the family). Goshen (<em>gōšen</em>) is consistently identified with the eastern Nile Delta, likely the Wadi Tumilat or the area near the later city of Rameses (47:11). Archaeological work at Tell el-Dab&#8217;a in this region has found evidence of a large Semitic-speaking population in the Second Intermediate Period (c. 1650&#8211;1550 BCE), consistent with the Genesis account&#8217;s localization of the Israelite settlement in the Delta.</p>",
"29": "<p>Joseph&#8217;s chariot journey to meet Jacob reverses the normal social dynamic: the powerful subordinate travels to meet the elderly father rather than the father traveling to the seat of power. &#8220;He threw his arms around his father and wept for a long time&#8221; — the reunion weeping (Heb. <em>wayyēbk ʿōd</em>, &#8220;he wept still more/a long time&#8221;) is the emotional climax of the entire Joseph narrative. The estrangement began with a robe dipped in blood (37:31&#8211;33); it ends with the embrace of the one presumed dead. In ANE royal portraiture, high officials did not display such emotion; the narrative&#8217;s emphasis on weeping marks this as a private family moment, not a state occasion.</p>",
"30": "<p>&#8220;Now I am ready to die, since I have seen for myself that you are still alive.&#8221; Jacob&#8217;s statement echoes the Nunc Dimittis of Simeon (Luke 2:29&#8211;32) in structure: having seen what he longed to see, the speaker is ready to depart. In the ANE context, a patriarch&#8217;s death required his eyes to be closed by a son (cf. v4&#8217;s promise); Jacob had been denied this for twenty-two years. The fulfilled promise — Joseph&#8217;s own hand will close his eyes — becomes the ground for Jacob&#8217;s contentment with death. He has seen the impossible become real and can rest.</p>",
"31": "<p>Joseph&#8217;s political strategy begins immediately: he will present the family to Pharaoh as shepherds to secure their settlement in Goshen. The phrase &#8220;I will go up and speak to Pharaoh&#8221; signals Joseph&#8217;s continued management of the family&#8217;s interface with Egyptian power. Navigating the family into the right administrative category — pastoral rather than agricultural — requires careful presentation. Joseph is not deceiving Pharaoh but managing the disclosure to achieve the best outcome: isolation in Goshen rather than integration into the Egyptian agrarian economy.</p>",
"32": "<p>&#8220;The men are shepherds; they tend livestock&#8221; — Joseph&#8217;s framing is accurate (the family are indeed shepherds) and strategic. He emphasizes the pastoral character of the family&#8217;s economy to position them for Goshen, where pasturage was available. The explicit mention of &#8220;flocks and herds and everything they own&#8221; presents them as self-sufficient economically, not as refugees who will burden Egyptian resources — an important distinction for how Pharaoh receives them.</p>",
"33": "<p>Joseph coaches the brothers on their answer before the audience with Pharaoh — the preparation for a royal audience reflects ANE court protocol. Pharaoh&#8217;s opening question &#8220;What is your occupation?&#8221; is a standard administrative inquiry used to categorize foreign settlers. Giving the wrong answer — for instance, claiming to be farmers or craftsmen — might result in absorption into the Egyptian agricultural workforce rather than separate settlement in Goshen. The scripted answer is diplomatic coaching, not deception.</p>",
"34": "<p>&#8220;All shepherds are detestable to the Egyptians&#8221; (<em>kî-tôʿăbaṯ miṣrayim kol-rōʿēh ṣōʾn</em>) — the basis for this claim in Egyptian culture is debated. Egyptian texts generally do not express blanket disdain for pastoralists, though there is evidence of negative Egyptian attitudes toward Semitic nomads (<em>ʿĀmu</em>) who entered the Delta region. The Hyksos, a Semitic people who dominated Egypt c. 1650&#8211;1550 BCE, may have been associated with pastoral lifestyles in Egyptian memory, making their successors suspect. Whatever the precise cultural logic, the pastoral/agricultural distinction creates the social separation that preserves Israel&#8217;s identity: settled in Goshen apart from the main Egyptian population, the family can remain a distinct people rather than being absorbed into Egyptian society.</p>"
},
"47": {
"1": "<p>Joseph&#8217;s presentation of his family to Pharaoh opens with the claim that they are &#8220;now in Goshen&#8221; — a fait accompli that invites Pharaoh to ratify an existing situation rather than decide on a hypothetical. This is a diplomatic move: by the time Pharaoh hears the request, the family has already arrived and settled in the area, making refusal more difficult and acceptance more natural. Joseph presents Pharaoh with a situation to bless rather than a petition to deny.</p>",
"2": "<p>&#8220;He chose five of his brothers and presented them before Pharaoh.&#8221; Why five? The narrative does not say. Five was a number with symbolic significance in Egyptian administrative contexts (one-fifth tax in v24; five cities in Isa 19:18); it may also reflect a deliberate selection of the most presentable brothers, or simply a conventional diplomatic delegation size for a court audience. The choice to present representatives rather than all ten brothers reflects an understanding of Pharaoh&#8217;s time and court protocol: a delegation of five is manageable, while eleven adult Semitic men appearing before the throne might create a different impression.</p>",
"3": "<p>Pharaoh&#8217;s question &#8220;What is your occupation?&#8221; — precisely the question Joseph predicted — receives the coached answer: &#8220;Your servants are shepherds, just as our fathers were.&#8221; The framing &#8220;just as our fathers were&#8221; presents pastoral life not as a temporary economic condition but as a multigenerational identity. This is important for the settlement claim: they are not migrants seeking employment but a pastoral people seeking grazing territory for their herds, consistent with the land of Goshen&#8217;s character.</p>",
"4": "<p>The brothers&#8217; formal petition — &#8220;We have come to live here for a while&#8221; (<em>lāgûr bāʾāreṣ bāʾnû</em>, &#8220;to sojourn in the land we have come&#8221;) — uses the <em>gēr</em> root (sojourner/resident alien), the same word Jacob uses for his own life in v9. The <em>gēr</em> status in ANE law was a recognized legal category: resident aliens who lived under the protection of the host society without full citizenship rights. By self-designating as <em>gērîm</em>, the brothers are requesting the recognized social category of protected resident aliens, not full Egyptian integration.</p>",
"5": "<p>Pharaoh&#8217;s response to Joseph rather than to the brothers signals the mediated nature of the audience: Pharaoh is addressing himself to his vizier who has brought the family. &#8220;Your father and your brothers have come to you&#8221; acknowledges the family relationship&#8212;Pharaoh is granting the settlement as a favor to Joseph, his most trusted official, as much as a grant to the family itself. The patron-client relationship between Pharaoh and Joseph is extended to cover Joseph&#8217;s entire family.</p>",
"6": "<p>&#8220;The land of Egypt is before you; settle your father and your brothers in the best part of the land&#8221; — Pharaoh&#8217;s grant is generous and unreserved. &#8220;If you know of any among them with special ability, put them in charge of my own livestock&#8221; — Pharaoh&#8217;s offer of employment for able brothers shows that the Egyptian court&#8217;s initial concern about Semitic shepherds does not preclude using skilled ones in royal service. The offer of stewardship over Pharaoh&#8217;s own herds is a significant honor; it would place brothers in a client-relationship with the royal household directly.</p>",
"7": "<p>Jacob blessed Pharaoh — the greater patriarch blesses the greater earthly king. The author of Hebrews (7:7) cites a different instance but the principle holds: &#8220;the lesser is blessed by the greater.&#8221; In the narrative&#8217;s logic, the covenant patriarch who carries the blessing of Abraham (through whom all nations will be blessed, Gen 12:3) blesses the most powerful ruler of the known world. Egypt&#8217;s hospitality to Israel becomes the occasion for Pharaoh to receive the blessing mediated through the covenant people&#8212;a reversal of apparent power: the elderly homeless patriarch stands before the great king and blesses him.</p>",
"8": "<p>Pharaoh&#8217;s question &#8220;How old are you?&#8221; is a court courtesy in Egyptian culture&#8212;inquiring after the age of an elderly honored guest was a mark of respect. In Egyptian wisdom literature, the aged were repositories of experience and wisdom; an old man commanding the presence of Pharaoh&#8217;s vizier would be a figure of obvious significance. The question also sets up Jacob&#8217;s remarkable answer in v9, which frames his 130 years not as an achievement but as a burden.</p>",
"9": "<p>&#8220;The years of my pilgrimage are a hundred and thirty.&#8221; Jacob&#8217;s use of <em>mĕgûray</em> (&#8220;my sojournings/pilgrimages&#8221;) rather than &#8220;my life&#8221; or &#8220;my years&#8221; is striking: he describes his 130 years entirely in terms of the <em>gēr</em> (sojourner) identity. His whole life has been one of displacement&#8212;fleeing from Esau, laboring in Paddan Aram, returning to Canaan, now going to Egypt. &#8220;Few and difficult&#8221; (<em>mĕʿaṭ wĕrāʿîm</em>) is a remarkable self-assessment for 130 years: compared to his fathers (Abraham 175, Isaac 180), 130 seems &#8220;few&#8221;; &#8220;difficult&#8221; is the honest testimony of his wrestling, his losses, his grief. Jacob before Pharaoh gives the most honest autobiography in the patriarchal narratives.</p>",
"10": "<p>Jacob blesses Pharaoh a second time upon departing — the blessing forms a frame around the audience (v7 entering, v10 leaving), indicating that the encounter is a formally complete blessing-event, not a casual meeting. In ANE court protocol, the beginning and end of an audience were marked by formal gestures; Jacob&#8217;s double blessing gives the encounter a liturgical structure. The covenant patriarch&#8217;s blessing over the Egyptian king establishes the theological principle that Israel&#8217;s presence in Egypt is, at least initially, a blessing to Egypt rather than a burden.</p>",
"11": "<p>The &#8220;district of Rameses&#8221; (<em>ʾereṣ Ramesēs</em>) is an anachronistic or proleptic reference: the city of Rameses was built (or rebuilt) by Ramesses II (c. 1279&#8211;1213 BCE), later than most datings of Joseph. The narrator uses the name the audience would recognize for the region rather than the name current in Joseph&#8217;s time (the area was earlier called Avaris). This is a standard ancient historiographical practice: using the name by which a place is known to the current audience rather than the name it bore in the distant past.</p>",
"12": "<p>Joseph provides food for his father, brothers, and all his father&#8217;s household &#8220;according to the number of their children&#8221; (<em>lĕpî haṭṭap</em>, lit. &#8220;according to the little ones&#8221;). The phrase implies a per-capita food allocation that explicitly includes the children&#8212;the most vulnerable members of the family. Joseph&#8217;s care for the family extends from official policy (managing Egypt&#8217;s grain supply) to personal provision (ensuring his own family is fed). The same man who was sold into slavery by his brothers now sustains their survival.</p>",
"13": "<p>&#8220;There was no food, however, in the whole region because the famine was severe; both Egypt and Canaan wasted away.&#8221; The severity of the famine is reiterated to contextualize the economic policies of vv14&#8211;26. The verb <em>wayyillāh</em> (&#8220;wasted away/languished&#8221;) is the same used for weakening from hunger; Egypt and Canaan alike are depicted as suffering (despite Egypt&#8217;s stores), because even stored grain runs out when distribution cannot keep pace with need and purchasing power collapses.</p>",
"14": "<p>Joseph&#8217;s systematic economic management: first phase — money. He collects all money in Egypt and Canaan in exchange for grain and delivers it to Pharaoh&#8217;s palace. This represents a massive monetization of the grain economy during crisis; in normal times, grain was traded in complex credit and barter systems. The concentration of precious metal in Pharaoh&#8217;s treasury through food sales is not uniquely biblical — Egyptian administrative texts record the state&#8217;s role in managing commodity exchange during shortage periods, with palace treasuries accumulating during crisis and redistributing afterward.</p>",
"15": "<p>Second economic phase: when money runs out, the population comes to Joseph. The Egyptians&#8217; appeal — &#8220;Give us food. Why should we die before your eyes?&#8221; — uses the patron-client petition formula. &#8220;Our money is used up&#8221; (<em>kilyāh hakkeseṗ</em>) marks the end of the first phase of exchange. In ANE economics, precious metal was relatively scarce; a sustained famine could exhaust the private money supply in a few years. The population&#8217;s appeal to the vizier as patron to grant life is consistent with the honor-shame patronage system where powerful patrons were expected to protect their dependents.</p>",
"16": "<p>Second phase: livestock exchange. &#8220;Bring your livestock&#8212;I will sell you food in exchange for your livestock, since your money is gone.&#8221; Joseph accepts horses, sheep, goats, cattle, and donkeys as payment. In ANE barter economies during monetary collapse, livestock served as an alternative store of value. The transition from money to barter reflects the progressive erosion of private economic capacity under sustained famine. Horses specifically were high-value animals in the ancient Near East (imported from Central Asia and the northern steppes); their inclusion signals that even wealthy Egyptians were participating in the asset-for-food exchange.</p>",
"17": "<p>Joseph &#8220;brought them through that year with food in exchange for all their livestock&#8221; — the exchange is complete for year one of the barter phase. The herd exchange effectively transferred Egypt&#8217;s private livestock economy to Pharaoh&#8217;s control. In Egyptian economic history, royal herds were substantial and included cattle and donkeys used for agricultural labor. By the end of the livestock phase, the crown controlled not just grain but the animal labor force needed to work the land — a comprehensive consolidation of the agricultural economy.</p>",
"18": "<p>Third phase begins: having exhausted money and livestock, the Egyptians offer themselves and their land. &#8220;There is nothing left for our lord except our bodies and our land&#8221; — the progression from money to cattle to land and person is consistent with ANE debt-slavery and land-transfer law. Mesopotamian legal texts (Old Babylonian period) document the progression by which families in debt during famine transferred first moveable assets, then real property, then labor into debt-service. The Egyptians are navigating a recognized legal trajectory.</p>",
"19": "<p>&#8220;Buy us and our land in exchange for food, and we with our land will be in bondage to Pharaoh.&#8221; The self-designation as bondservants (<em>wĕnihyeh ʾănaḥnû wĕʾarṣēnû ʿăbādîm lĕparʿōh</em>) is a voluntary submission to debt-servitude in exchange for survival. In ANE and later biblical law, debt-servitude was a recognized legal institution that protected debtors from creditors taking everything without recourse: the debtor surrendered labor but retained personhood. The Egyptians are not offering chattel slavery but the recognized institution of bound labor in exchange for food and seed.</p>",
"20": "<p>&#8220;Joseph bought all the land in Egypt for Pharaoh.&#8221; The land transfer represents the most dramatic economic transformation in Genesis: all privately owned agricultural land in Egypt is transferred to the crown in a single famine-driven transaction. Egyptian administrative history does not corroborate this level of royal land monopoly (temples, nobles, and individuals held land throughout Egyptian history), but the narrative presents it as the origin of royal land tenure in Egypt. Whether historical or etiological, the story explains the basis for Egyptian land law from an Israelite perspective.</p>",
"21": "<p>&#8220;Joseph reduced the people to servitude from one end of Egypt to the other.&#8221; The text is variously translated: the Samaritan Pentateuch and LXX read &#8220;he transferred the people to the cities&#8221; (internal migration for labor distribution), while the Hebrew MT reads &#8220;he passed them over to the cities&#8221; (also possibly relocation). Either reading reflects the administrative reality that a centralized agricultural economy requires organized labor distribution. Whether this constitutes &#8220;slavery&#8221; in the chattel sense or bound agricultural labor (serfdom) is debated; the 20% tax arrangement in v24 suggests the latter — serfs retained 80% of their produce.</p>",
"22": "<p>The exemption of priestly land is corroborated by Egyptian history: temple estates in Egypt were tax-exempt and held special administrative status throughout the pharaonic period. The Wilbour Papyrus (c. 1143 BCE) documents extensive temple land holdings that operated outside normal state taxation. The Genesis account&#8217;s acknowledgment of priestly exemption is one of its most archaeologically consistent details — a narrator familiar with Egyptian institutions would know that priests&#8217; land was not subject to the same pressure as private holdings, and would include this exception to represent the policy accurately.</p>",
"23": "<p>Joseph&#8217;s distribution of seed grain after the land acquisition signals that the policy is redistribution, not abandonment: the people get seed to plant the crown&#8217;s land, establishing a sharecropping arrangement. &#8220;Now that I have bought you and your land today for Pharaoh, here is seed for you so you can plant the ground.&#8221; The provision of seed is essential — without it, the famine&#8217;s end cannot produce crops, and the newly acquired land becomes worthless. Joseph&#8217;s practical concern is productivity, not punishment.</p>",
"24": "<p>&#8220;Give a fifth of it to Pharaoh. The other four-fifths you may keep.&#8221; The 20% crown-tax established here mirrors precisely the tax Joseph proposed in 41:34 during the abundance years — both as storage levy and now as permanent land-use fee. In comparative ANE taxation, 20% is a moderate-to-heavy rate (Mesopotamian palace rents ranged from 10&#8211;50%); Egyptian temple rents documented in later papyri ran 10&#8211;20%. The narrative presents Joseph&#8217;s arrangement as sustainable and humane within ANE norms — the people retain 80% for seed, food, and household use.</p>",
"25": "<p>&#8220;You have saved our lives,&#8221; they said. &#8220;May we find favor in the eyes of our lord; we will be in bondage to Pharaoh.&#8221; The Egyptians&#8217; response frames the economic transformation as salvation rather than exploitation — they consent to the arrangement as preferable to starvation. In honor-shame terms, the patron who provides life deserves and receives loyalty: the surrender of economic independence to the crown is presented as a rational and even grateful response to Joseph&#8217;s management of the crisis. The narrative does not present the policy as oppression from the Egyptian perspective.</p>",
"26": "<p>&#8220;Joseph established it as a law concerning land in Egypt — still in force today.&#8221; The etiological formula &#8220;still in force today&#8221; (<em>ʿad hayyôm hazzeh</em>) signals that the narrator is explaining a current (from their perspective) Egyptian institution by tracing it to Joseph. The claim that the 20% crown-tax originated with Joseph is presented as historical memory of how Egyptian land tenure was reorganized during a famine. The priestly exemption is reiterated — &#8220;it was only the land of the priests that did not become Pharaoh&#8217;s&#8221; — closing the land-policy narrative with its notable exception.</p>",
"27": "<p>&#8220;The Israelites settled in Egypt in the region of Goshen. They acquired property there and were fruitful and increased greatly in number.&#8221; The fruitfulness language (<em>wayyiprû wayyirbû mĕʾōd</em>) directly echoes the creation blessing (Gen 1:28) and the Abrahamic promise (17:6, 20). Egypt, the alien land, becomes the place where the covenant promise of numerical multiplication is dramatically fulfilled. This is the narrative preparation for Exodus 1:7&#8217;s nearly identical language describing the population explosion that alarmed Pharaoh: Genesis&#8217;s &#8220;fruitful and increased greatly&#8221; becomes Exodus&#8217;s &#8220;fruitful and increased greatly and multiplied and became exceedingly strong.&#8221;</p>",
"28": "<p>Jacob lived seventeen years in Egypt, dying at 147. The seventeen-year Egypt period mirrors the seventeen years Joseph spent with his father before being sold (37:2) — Joseph was seventeen when the separation occurred; Jacob now lives with Joseph for seventeen years in Egypt before dying. The numerical symmetry is likely deliberate: the years of relationship lost are exactly matched by the years of relationship restored. The patriarchal lifespans (Abraham 175, Isaac 180, Jacob 147) show a progressive decline, reflecting the narrowing of the patriarchal era toward the tribal-national period.</p>",
"29": "<p>&#8220;Put your hand under my thigh and promise.&#8221; The oath formula placing the hand under the thigh (<em>śîm yādĕḵā taḥaṯ yĕrēḵî</em>) appears also in Gen 24:2 when Abraham sends his servant to find Isaac&#8217;s wife. The thigh (euphemism for the genitals, the seat of procreation and of the covenant of circumcision) invokes the Abrahamic covenant itself as the ground of the oath: &#8220;swear by the source of the covenant community that you will honor covenant loyalty.&#8221; &#8220;Unfailing loyalty and faithfulness&#8221; (<em>ḥeseḏ wĕ ʾĕmeṯ</em>) is the covenant-loyalty formula; Jacob is requesting that Joseph fulfill covenant obligations to him that transcend the Egyptian context.</p>",
"30": "<p>&#8220;Carry me out of Egypt and bury me where they are buried.&#8221; The burial request for the Cave of Machpelah (where Abraham, Sarah, Isaac, Rebekah, and Leah were buried, ch 23; 25:9; 35:29; 49:31) is not merely personal preference but covenant testimony: Jacob&#8217;s burial in Canaan is a physical declaration that Egypt is not the covenant people&#8217;s ultimate home. In ANE and Egyptian burial practice, being buried in one&#8217;s ancestral land was essential for rest; burial in foreign soil was considered a tragedy. Jacob&#8217;s request insists on the covenant geography even after death.</p>",
"31": "<p>&#8220;Then Israel worshiped as he leaned on the top of his staff.&#8221; The Hebrew (<em>wayyišṯaḥû yiśrāʾēl ʿal-rōʾš hammiṭṭāh</em>) has two possible readings: <em>miṭṭāh</em> (bed) or <em>maṭṭeh</em> (staff) — the Hebrew consonants are identical and only the vowel pointing distinguishes them. The MT reads &#8220;the top of the bed&#8221; (Jacob worshiped from his sickbed); the LXX reads &#8220;the top of his staff&#8221; (Jacob stood and worshiped leaning on his walking staff). Hebrews 11:21 follows the LXX: &#8220;by faith Jacob, when dying, blessed each of the sons of Joseph, worshiping as he leaned on the top of his staff.&#8221; Both readings are ancient; the staff reading presents a more active posture of faith; the bed reading a more realistic picture of a dying man.</p>"
},
"48": {
"1": "<p>&#8220;Some time later Joseph was told, &#8216;Your father is ill.&#8217;&#8221; The vague &#8220;some time later&#8221; indicates narrative compression; the seventeen Egypt years pass quickly in the text (47:28). Joseph takes both sons to Jacob&#8217;s bedside&#8212;Manasseh and Ephraim will be the objects of the blessing scene. Bringing them specifically signals that Joseph has a purpose for this visit beyond filial duty: he intends for his father to bless his Egyptian-born sons and thereby incorporate them into the covenant family.</p>",
"2": "<p>Jacob &#8220;rallied his strength and sat up on the bed&#8221; at news of Joseph&#8217;s arrival. The act of sitting up from a deathbed is an expression of honor toward the visitor — in ANE and later Jewish etiquette, rising or sitting up for an honored person was a physical demonstration of respect even when physically difficult. The text notes Jacob&#8217;s physical effort (<em>wayyitḥazzēq yiśrāʾēl</em>, &#8220;Israel strengthened himself&#8221;) to signal that what follows is not casual conversation but a formal, deliberate act requiring full cognitive and spiritual presence.</p>",
"3": "<p>Jacob invokes his most recent theophany: &#8220;God Almighty appeared to me at Luz in the land of Canaan.&#8221; Luz = Bethel (Gen 28:19; 35:6). The invocation of <em>ʾĒl Šaddāy</em> (God Almighty, the patriarchal name for God before the Mosaic revelation of YHWH, Exod 6:3) connects this blessing to the covenant framework established at Bethel. Jacob is not acting from personal sentiment but from divine mandate: the blessing he is about to give Ephraim and Manasseh is grounded in the Bethel covenant and is therefore valid regardless of Jacob&#8217;s personal preferences or family politics.</p>",
"4": "<p>Jacob recites the Bethel blessing: &#8220;I will make you fruitful and increase your numbers. I will make you a community of peoples, and I will give this land as an everlasting possession to your descendants after you.&#8221; This is the Abrahamic covenant formula (12:2; 17:6&#8211;8) now active in Jacob&#8217;s deathbed blessing. The covenant promises that Jacob received at Bethel are the authorization for what he is about to do: adopting Joseph&#8217;s sons extends the covenant line, creates two additional tribes in the land promise, and anchors everything in divine initiative rather than human decision.</p>",
"5": "<p>The adoption formula: &#8220;Your two sons born to you in Egypt before I came to you here will be reckoned as mine; Ephraim and Manasseh will be mine, just as Reuben and Simeon are mine.&#8221; In ANE adoption law (attested in Nuzi tablets, Old Babylonian texts, and Hammurabi&#8217;s code), an adopting father&#8217;s declaration &#8220;you are my son&#8221; or &#8220;he is as my son&#8221; was the operative legal formula that transferred inheritance rights. Jacob&#8217;s declaration is a formal adoption that makes Manasseh and Ephraim full tribal patriarchs equivalent to Jacob&#8217;s biological sons. Joseph receives a double portion (two tribes instead of one) — the legal right of the firstborn (Deut 21:17), given to Joseph as the firstborn of Rachel, Jacob&#8217;s beloved wife.</p>",
"6": "<p>&#8220;Any children born to you after them will be yours; in the territory they inherit they will be reckoned under the names of their brothers.&#8221; The legal precision is significant: Joseph could have additional sons (he is approximately 56 at this point), and their status is clearly defined. They will be subordinate to the two adopted sons and counted within Ephraim or Manasseh&#8217;s tribal territory rather than receiving independent tribal allotments. The adoption of only Manasseh and Ephraim is a deliberate limitation that creates exactly the tribal structure Israel will have: twelve tribes with Joseph replaced by Ephraim + Manasseh, and Levi receiving no territorial allotment (as the priestly tribe).</p>",
"7": "<p>Jacob&#8217;s explanation for the special treatment of Ephraim and Manasseh is unexpected: he invokes Rachel&#8217;s death. &#8220;As I was returning from Paddan, to my sorrow Rachel died&#8230;&#8221; By giving Joseph a double portion (two tribes), Jacob is compensating posthumously for Rachel — the wife he loved most, who died before inheriting with Jacob in Canaan, whose sons were taken from him. The connection to Rachel&#8217;s burial place near Bethlehem is a geographical marker that links this deathbed scene to the covenant landscape of Canaan. Bethlehem will later be the city of David and the birthplace of Jesus.</p>",
"8": "<p>&#8220;When Israel saw the sons of Joseph, he asked, &#8216;Who are these?&#8217;&#8221; Jacob&#8217;s question is surprising given that Manasseh and Ephraim have lived in Egypt for years and Jacob has been in Egypt seventeen years. The question is either a test of the formal adoption ritual (requiring Joseph to formally present his sons as petitioning for blessing), or it reflects Jacob&#8217;s failing eyesight (noted in v10). In ANE adoption ceremonies, formal presentation of the adoptee to the adopting father was part of the legal procedure; Jacob&#8217;s question may initiate the formal presentation sequence.</p>",
"9": "<p>Joseph&#8217;s answer — &#8220;They are the sons God has given me here&#8221; — acknowledges both the divine gift and the Egyptian location (&#8220;here&#8221;). Jacob&#8217;s response — &#8220;Bring them to me so I may bless them&#8221; — is the patriarch&#8217;s formal acceptance of the presentation. The blessing by the patriarch was a legal act in ANE kinship law: the father&#8217;s blessing conferred status, inheritance rights, and covenant standing. Isaac&#8217;s blessing of Jacob and Esau (ch 27) shows that the patriarchal blessing was legally binding and irrevocable once given. Jacob is about to perform the same irrevocable legal act for Joseph&#8217;s sons.</p>",
"10": "<p>&#8220;Israel&#8217;s eyes were failing because of old age, and he could hardly see.&#8221; This detail is not merely biographical; it echoes the narrative of Isaac&#8217;s blind eyes in ch 27, the deception in which Jacob received the firstborn blessing through a reversal of birth-order. Now Jacob himself has failing eyes — but unlike Isaac, who was deceived into giving the wrong blessing, Jacob will deliberately and knowingly cross his hands to give the younger son the greater blessing. The irony is precise: the son who received blessing through deception of a blind father will give blessing through deliberate action despite his own failing sight.</p>",
"11": "<p>&#8220;I never expected to see your face again, and now God has allowed me to see your children too.&#8221; Jacob&#8217;s gratitude is framed entirely in terms of divine gift: the reunion with Joseph, the sight of his grandsons, are more than he deserved or expected. The phrase &#8220;God has allowed me to see&#8221; (<em>hirʾāh ʾōtî ʾĕlōhîm</em>) — literally &#8220;God has shown me&#8221; — attributes his survival and the reunion entirely to divine provision. The statement also acknowledges that Jacob is near death: seeing the grandsons is a final gift before closing his eyes.</p>",
"12": "<p>Joseph&#8217;s prostration &#8220;with his face to the ground&#8221; before Jacob is a formal gesture of filial reverence appropriate to the gravity of the blessing ceremony. &#8220;He removed them from Israel&#8217;s knees&#8221; — the grandchildren had been sitting on Jacob&#8217;s knees, the posture of adoption in ANE custom (cf. Gen 30:3 where Bilhah&#8217;s children are &#8220;born on Rachel&#8217;s knees&#8221; = adopted by Rachel). Joseph removes them from the adoption-posture and positions them for the blessing, with Manasseh (firstborn) placed to receive Jacob&#8217;s right hand and Ephraim (younger) placed to receive Jacob&#8217;s left hand.</p>",
"13": "<p>Joseph&#8217;s careful positioning — Ephraim on his right toward Israel&#8217;s left, Manasseh on his left toward Israel&#8217;s right — follows the expected protocol: the firstborn Manasseh should receive the right hand (the stronger blessing hand). In ANE symbolic gesture, the right hand conveyed greater blessing, authority, and status; the left hand was the lesser (cf. Matt 25:33 right/left distinction). Joseph has done everything correctly according to birth-order protocol. Jacob is about to deliberately reverse it.</p>",
"14": "<p>&#8220;Israel reached out his right hand and put it on Ephraim&#8217;s head, though he was the younger, and crossing his arms&#8212;&#8221; The Hebrew verb for &#8220;crossing&#8221; (<em>śikkēl</em>, Piel of <em>śākal</em>) means &#8220;to act wisely/prudently&#8221; or &#8220;to cross deliberately.&#8221; The Piel form is intensive: Jacob crossed his hands with full intentional wisdom, not by accident or confusion (his eyes were poor but his mind was clear). The same root will appear in v19 when he insists he knows what he is doing (&#8220;I know, my son, I know&#8221;). This is the reversal of firstborn priority — the same pattern that runs through Genesis: the younger chosen over the older (Abel/Cain in God&#8217;s regard, Isaac/Ishmael, Jacob/Esau, Joseph/Reuben).</p>",
"15": "<p>The blessing invokes God under three complementary descriptions: &#8220;the God before whom my fathers Abraham and Isaac walked&#8221; — the covenantal God of the patriarchal promise-history; &#8220;the God who has been my shepherd all my life to this day&#8221; — the personal providential God who has guided Jacob; and (v16) &#8220;the Angel who has delivered me from all harm&#8221; — the mediating divine figure who intervened personally (cf. the wrestling angel of 32:24&#8211;30). The three-part divine description is not a trinitarian formula but a comprehensive invocation of God as covenant-keeper, shepherd, and personal redeemer — all three aspects participating in the blessing.</p>",
"16": "<p>&#8220;The Angel who has delivered me from all harm&#8221; (<em>hammalʾāk haggōʾēl ʾōtî mikkol-rāʿ</em>) — the term <em>gōʾēl</em> is the kinsman-redeemer, the family member obligated to rescue a relative from slavery, debt, or danger (Lev 25:25; Ruth 2:20; 3:12). Applying this term to a divine &#8220;angel&#8221; who redeems Jacob is theologically significant: God functions as Jacob&#8217;s kinsman, taking on the role of family-redeemer on Jacob&#8217;s behalf. &#8220;May they be called by my name and the names of my fathers Abraham and Isaac&#8221; — the naming formula signals full legal adoption into the covenant line; the boys&#8217; Egyptian birth does not prevent them from bearing the patriarchs&#8217; covenantal identity.</p>",
"17": "<p>Joseph&#8217;s displeasure and his attempt to correct his father&#8217;s hands is the narrative&#8217;s moment of dramatic tension. Joseph has managed his family&#8217;s affairs in Egypt with political precision; here he tries to &#8220;manage&#8221; his father&#8217;s blessing according to proper protocol. His hand on Jacob&#8217;s hand is a filial intervention, physically trying to redirect the blessing. The scene parallels Isaac&#8217;s discovery that he had blessed the wrong son — but here, the patriarch acts knowingly and the son&#8217;s intervention fails. Joseph cannot override his father&#8217;s deliberate prophetic act.</p>",
"18": "<p>&#8220;No, my father, this one is the firstborn; put your right hand on his head.&#8221; Joseph&#8217;s protest is legalistic — he invokes the firstborn-priority rule as the grounds for correction. His understanding of how blessing should work is shaped by inheritance law and social convention. Jacob&#8217;s response transcends those conventions: the covenant has always moved through chosen rather than natural succession. Joseph knows the history but apparently believes his sons will be an exception to the pattern.</p>",
"19": "<p>&#8220;I know, my son, I know. He too will become a people, and he too will become great. Nevertheless, his younger brother will be greater than he, and his descendants will become a group of nations.&#8221; The repeated &#8220;I know&#8221; (<em>yāḏaʿtî bĕnî yāḏaʿtî</em>) is emphatic reassurance and mild rebuke simultaneously: I am not mistaken, I am acting in full awareness of what I am doing. &#8220;A group of nations&#8221; (<em>mĕlōʾ haggôyim</em>, &#8220;fullness of nations&#8221;) — the phrase anticipates Ephraim&#8217;s descendants becoming the dominant force in the northern ten tribes and eventually the largest single tribal territory. Ephraim became so prominent that the northern kingdom was called &#8220;Ephraim&#8221; in prophetic literature (Isa 7:2; Hos 5:3).</p>",
"20": "<p>&#8220;In your name will Israel pronounce this blessing: &#8216;May God make you like Ephraim and Manasseh.&#8217;&#8221; The blessing becomes proverbial: future Israelite blessing-formulas would invoke Ephraim before Manasseh as the standard of divine favor. The reversal of birth-order is institutionalized in the liturgical formula itself — every Israelite father who uses this blessing acknowledges that God&#8217;s election overrides human convention. &#8220;So he put Ephraim ahead of Manasseh&#8221; — the narrator&#8217;s closing note confirms the order is permanent, not provisional.</p>",
"21": "<p>&#8220;I am about to die, but God will be with you and take you back to the land of your fathers.&#8221; Jacob&#8217;s dying word to Joseph is a covenant promise rather than personal advice: the God who went down with Jacob to Egypt will bring Joseph and his descendants back to Canaan. The promise anticipates the Exodus without naming it. Joseph will take this prophecy seriously enough to make the Israelites swear to carry his bones back to Canaan (50:24&#8211;25), an oath fulfilled in Joshua 24:32. The &#8220;God will be with you&#8221; assurance echoes the theophanic assurance of 46:4 and the entire pattern of divine accompaniment in Genesis.</p>",
"22": "<p>&#8220;To you I give one more ridge of land than to your brothers, the ridge I took from the Amorites with my sword and my bow.&#8221; The Hebrew <em>šĕkem ʾaḥaḏ</em> is literally &#8220;one shoulder/ridge/portion.&#8221; <em>Šĕkem</em> is also the name of the city Shechem — a deliberate wordplay. Jacob may be referring to the land purchased at Shechem (33:19) or to a military action not otherwise recorded. John 4:5 locates the &#8220;plot of ground Jacob had given to his son Joseph&#8221; near Sychar (a variant of Shechem), connecting this verse to the geography of Jesus&#8217; encounter with the Samaritan woman. The double meaning — literal land-grant plus Shechem-wordplay — gives the verse both concrete legal and symbolic resonance.</p>"
}
}

def main():
    existing = load_comm('mkt-context', 'genesis')
    merge_comm(existing, NEW_DATA)
    save_comm('mkt-context', 'genesis', existing)
    print(f"  ch46 verses: {len(existing.get('46', {}))}")
    print(f"  ch47 verses: {len(existing.get('47', {}))}")
    print(f"  ch48 verses: {len(existing.get('48', {}))}")
    print("Genesis 46–48 mkt-context written.")

if __name__ == '__main__':
    main()
